def generate_fallback_description(item):
    ds_name = item.get("dataset", {}).get("name")
    source_name = item.get("dataset", {}).get("source", {}).get("name")
    if ds_name and source_name:
        return f"Dataset containing '{ds_name}' statistics, tracked and provided by {source_name}."
    return f"Statistical data corresponding to {item.get('name', item.get('dcid'))}."

def main():
    with open(input_file, 'r') as f:
        data = json.load(f)
        
    for item in data:
        dcid = item.get("dcid")
        if dcid in RICH_DESCRIPTIONS:
            item["description"] = RICH_DESCRIPTIONS[dcid]
        else:
            # Fallback for any missed items out of the 192
            item["description"] = generate_fallback_description(item)
            
    with open(output_file, 'w') as f:
        json.dump(data, f, indent=2)
        
    print(f"Successfully generated rich data descriptions for {len(data)} provenances.")
    print(f"Saved to {output_file}")

if __name__ == "__main__":
    main()
